Test cases for the JSON Config Merger Utility

These tests cover basic functionality and edge cases of the merge and validation functions.
"""

import unittest
from eval36_merger import merge_configs, validate_merge


class TestMergeConfigs(unittest.TestCase):

    def test_shallow_merge(self):
        config1 = {'a': 1, 'b': 2}
        config2 = {'b': 3, 'c': 4}
        result = merge_configs(config1, config2)
        self.assertEqual(result, {'a': 1, 'b': 3, 'c': 4})

    def test_nested_merge(self):
        config1 = {'a': {'x': 1}, 'b': 2}
        config2 = {'a': {'y': 2}, 'b': 3}
        result = merge_configs(config1, config2)
        self.assertEqual(result, {'a': {'x': 1, 'y': 2}, 'b': 3})

    def test_list_concatenation(self):
        config1 = {'a': [1, 2]}
        config2 = {'a': [3, 4]}
        result = merge_configs(config1, config2)
        self.assertEqual(result, {'a': [1, 2, 3, 4]})

    def test_override_precedence(self):
        config1 = {'a': 1, 'b': 2}
        config2 = {'a': 3, 'b': 4}
        result = merge_configs(config1, config2)
        self.assertEqual(result, {'a': 3, 'b': 4})

    def test_type_conflict_detection(self):
        config1 = {'a': 1}
        config2 = {'a': '2'}
        conflicts = validate_merge(config1, config2)
        self.assertEqual(conflicts, ["Key 'a' has conflicting types: int, str"])

    def test_empty_input_handling(self):
        config1 = {}
        config2 = {}
        result = merge_configs(config1, config2)
        self.assertEqual(result, {})
        conflicts = validate_merge(config1, config2)
        self.assertEqual(conflicts, [])


if __name__ == '__main__':
    unittest.main()"}

